            isShow: false\r\n                },\r\n                {\r\n                    title: 'CompanyNotification',\r\n                    icon: 'fa fa-bell',\r\n                    goTo: '/CompanyNotification/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'ContactType',\r\n                    icon: 'fa fa-list-alt',\r\n                    goTo: '/ContactType/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'CurrencyManagement',\r\n                    icon: 'fa fa-money',\r\n                    goTo: '/CurrencyManagement/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Department',\r\n                    icon: 'fa fa-users',\r\n                    goTo: '/Department/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Designation',\r\n                    icon: 'fa fa-address-card',\r\n                    goTo: '/Designation/Index',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'Discounts',\r\n                    icon: 'fa fa-usd',\r\n                    goTo: '/ClientBill/CreateDeductions',\r\n                    isShow: false\r\n                },\r\n                {\r\n                    title: 'EmailTemplate',\r\n                    icon: 'fa fa-file-text-o',\r\n                    goTo: '/EmailTemplate/Index',\r\n                    isShow: false\r\n                },\r\n                // {\r\n                //     title: 'SMS Template',\r\n                //     icon: 'fa fa-comments',\r\n                //     goTo: '/SMSTemplate/Index',\r\n                // },\r\n                {\r\n                    title: 'Feedback',\r\n                    icon: 'fa fa-quote-left',\r\n                    goTo: '/Feedback/Index