_TYPE\": \"string\",\r\n                        \"SORTABLE\": true,\r\n                        \"VISIBLE\": true,\r\n                        \"DISPLAY_NAME\": \"moduleName\",\r\n                        \"DISPLAY_ORDER\": 2\r\n                    },\r\n                    {\r\n                        \"COLUMN_NAME\": \"status_id\",\r\n                        \"DATA_TYPE\": \"string\",\r\n                        \"SORTABLE\": false,\r\n                        \"VISIBLE\": true,\r\n                        \"DISPLAY_NAME\": \"Status\",\r\n                        \"DISPLAY_ORDER\": 3,\r\n                        settings : {\r\n                                isInSlot: true\r\n                            }\r\n                    }],\r\n            ListingData:[],\r\n            PageSize: 10,\r\n            PageNumber: 1,\r\n            isPaged: 1,\r\n            TotalPages: 0,\r\n            widgets: [],\r\n            SortBy: '',\r\n            SortExp: '',\r\n            TotalRecords:0,\r\n            topsearchField : [             \r\n                {       \r\n                    fieldName: 'Search by CheckList Name',            \r\n                    fieldType: \"text\",\r\n                    fieldSearchConditionName: ['TC.checklist_name'],\r\n                    paramName: \"TC.checklist_name\",\r\n                    isSearch: true,\r\n                    value: \"\",\r\n                    listOptions: []\r\n                },\r\n            ],\r\n            IsAddCheckList:false,\r\n            CheckListStatus:[],\r\n            CheckListId:0,\r\n            userId: null,\r\n            companyId: null,\r\n            IsCloneCheckList:false\r\n        }\r\n    },\r\n    created:function(){\r\n        this.FetchCheckListing();\r\n        this.userId = this.GetUserInfo.ID;\r\n        this.companyId = this.GetUserInfo.CompanyId;  \r\n    },\r\n    updated(){        \r\n        const divElement = document.getElementsByClassName('ticketsmallfix theme-primary partit