ormSchema)[1].Data[1].value=vm.TaxData.code_id,\r\n            (vm.FormSchema)[1].Data[1].value=vm.TaxData.tax_country,\r\n            vm.OnChangeCountryList(vm.TaxData.tax_country)\r\n            (vm.FormSchema)[1].Data[2].value=vm.TaxData.tax_state,\r\n            vm.OnChangeStateList(vm.TaxData.tax_state)\r\n            (vm.FormSchema)[1].Data[3].value=vm.TaxData.tax_district,\r\n            vm.OnChangeDistrictList(vm.TaxData.tax_district)\r\n            (vm.FormSchema)[1].Data[4].value=vm.TaxData.tax_zipcode,\r\n            (vm.FormSchema)[1].Data[5].value=(vm.TaxData.tax_type=='percent') ? 100:200,\r\n            (vm.FormSchema)[1].Data[6].value=vm.TaxData.tax_rate,\r\n            (vm.FormSchema)[1].Data[7].value=vm.TaxData.status_id,\r\n            (vm.FormSchema)[1].Data[8].value=vm.TaxData.tax_rate.Priority,\r\n            (vm.FormSchema)[2].Data[1].value=vm.TaxData.tax_desc\r\n        }\r\n\r\n    },\r\n    methods: {\r\n        Close: function () {\r\n            this.$parent.AddItem = false;\r\n        },\r\n        GetRadioValue(data, event, getid) {           \r\n            var vm = this;\r\n            (vm.FormSchema)[1].Data[3].visibility = false;\r\n            (vm.FormSchema)[1].Data[4].visibility = false;\r\n            // (vm.FormSchema)[1].Data[5].visibility = false;\r\n\r\n            if (event.value == '2023' ) {\r\n                (vm.FormSchema)[1].Data[2].visibility = true;\r\n            }\r\n            if (event.value == '2024') {\r\n                (vm.FormSchema)[1].Data[2].visibility = true;\r\n                (vm.FormSchema)[1].Data[3].visibility = true;\r\n            }\r\n            if (event.value == '2025') {\r\n                (vm.FormSchema)[1].Data[2].visibility = true;\r\n                (vm.FormSchema)[1].Data[3].visibility = true;\r\n                (vm.FormSchema)[1].Data[4].visibility = true;\r\n            }\r\n        },\r\n        async GetStatusList() {          \r\n            var vm = this;\r\n            vm.isLoading = true;\r\n            await DataService.GetStatusList().then((response) => {                \r\n                if (JSON.parse(response.data) != null) {\r\n                    vm.SubCatData = [];\r\n                    vm.SubCatData = JSON.parse(response.data);\r\n                    vm.SubCatData.forEach((itm, index) => {\r\n                        if (itm.STATUS != 'Deleted') {\r\n                            (vm.FormSchema)[1].Data[7].config.options.push({\r\n                                name: itm.STATUS,\r\n                                value: itm.STATUS_ID\r\n                            })\r\n                        }\r\n                    })\r\n                    vm.$refs.dynamicform.UpdateKeyValue();\r\n                    vm.isLoading = false;\r\n                }\r\n                vm.isLoading = false;\r\n            });\r\n        },\r\n        // async GetTaxCode() {\r\n        //     var vm = this;\r\n        //     vm.isLoading = true;\r\n        //     await DataService.GetTaxCode().then((response) => {\r\n        //         if (response.data != null) {\r\n        //             vm.CodeData = [];\r\n        //             vm.CodeData = response.data;\r\n        //             vm.CodeData.forEach((itm, index) => {\r\n        //                 (vm.FormSchema)[1].Data[1].config.options.push({\r\n        //                     name: itm.codeName,\r\n        //                     value: itm.codeId\r\n        //                 })\r\n        //             })\r\n        //             vm.$refs.dynamicform.UpdateKeyValue();\r\n        //             vm.isLoading = false;\r\n        //         }\r\n        //         vm.isLoading = false;\r\n        //     });\r\n        // },\r\n        async GetCountryList() {\r\n            var vm = this;\r\n            vm.isLoading = true;\r\n            await DataService.GetCountryList().then((response) => {\r\n                if (response.data != null) {\r\n                    vm.CountryData = [];\r\n                    vm.CountryData = response.data;\r\n                    vm.CountryData.forEach((itm, index) => {\r\n                        (vm.FormSchema)[1].Data[1].config.options.push({\r\n                            name: itm.countrY_FULL_NAME,\r\n                            value: itm.id\r\n                        })\r\n                    })\r\n                    vm.$refs.dynamicform.UpdateKeyValue();\r\n                    vm.isLoading = false;\r\n                }\r\n                vm.isLoading = false;\r\n            });\r\n        },\r\n\r\n        OnChangeCountryList: async function (x) {\r\n            var vm = this;\r\n            (vm.FormSchema)[1].Data[2].config.options = [];\r\n            if ((vm.FormSchema)[1].Data[2].visibility == true) {               \r\n                vm.isLoading = true;\r\n                // var dropValue = x.value > 0 ? x.value : 0;\r\n                var dropValue = typeof x === 'object' ? x.target.value : x\r\n                var url = `CountryId=${dropValue}`;\r\n                await DataService.GetStateList(url).then((response) => {\r\n                    if (response.data != null) {\r\n                        vm.StateData = [];\r\n                        vm.StateData = response.data;\r\n                        vm.StateData.forEach((itm, index) => {\r\n                            (vm.FormSchema)[1].Data[2].config.options.push({\r\n                                name: itm.stateName,\r\n                                value: itm.stateId\r\n                            })\r\n                        })\r\n                        vm.$refs.dynamicform.UpdateKeyValue();\r\n                        vm.isLoading = false;\r\n                    }\r\n                    vm.isLoading = false;\r\n                });\r\n            }\r\n        },\r\n        OnChangeStateList: async function (x) {\r\n            var vm = this;\r\n            (vm.FormSchema)[1].Data[3].config.options = [];\r\n            if ((vm.FormSchema)[1].Data[3].visibility == true) {             \r\n                vm.isLoading = true;\r\n                // var dropValue = x.value > 0 ? x.value : 0;\r\n                var dropValue =  typeof x === 'object' ? x.target.value : x\r\n                var url = `StateId=${dropValue}`;\r\n                await DataService.GetDistrictListByStateId(url).then((response) => {\r\n                    if (response.data != null) {\r\n                        vm.DistrictData = [];\r\n                        vm.DistrictData = response.data;\r\n                        vm.DistrictData.forEach((itm, index) => {\r\n                            (vm.FormSchema)[1].Data[3].config.options.push({\r\n                                name: itm.districtName,\r\n                                value: itm.districtId\r\n                            })\r\n                        })\r\n                        vm.$refs.dynamicform.UpdateKeyValue();\r\n                        vm.isLoading = false;\r\n                    }\r\n                    vm.isLoading = false;\r\n                });\r\n            }\r\n        },\r\n        OnChangeDistrictList: async function (x) {\r\n            debugger\r\n            var vm = this;\r\n            (vm.FormSchema)[1].Data[4].config.options = [];\r\n            if ((vm.FormSchema)[1].Data[4].visibility == true) {             \r\n                vm.isLoading = true;\r\n                // var dropValue = x.value > 0 ? x.value : 0;\r\n                var dropValue =  typeof x === 'object' ? x.target.value : x\r\n                // var url = `StateId=${dropValue}`;\r\n                var url =`moduleName=CRM&type=DISTRICT_ZIPCODE&refId=${dropValue}`\r\n                await DataService.GetDDLData(url).then((response) => {\r\n                    debugger\r\n                    if (response.data != null) {\r\n                        vm.ZipCodeData = [];\r\n                        if(response.data.DATA.length>0)\r\n                        {\r\n                            vm.ZipCodeData = response.data.DATA;\r\n                            vm.ZipCodeData.forEach((itm, index) => {\r\n                                (vm.FormSchema)[1].Data[4].config.options.push({\r\n                                    name: itm.name,\r\n                                    value: itm.value\r\n                                })\r\n                            })\r\n                            vm.$refs.dynamicform.UpdateKeyValue();\r\n                        }\r\n                        vm.isLoading = false;\r\n                    }\r\n                    vm.isLoading = false;\r\n                });\r\n            }\r\n        },\r\n        onSubmit(formfields, val) {\r\n            var vm = this;\r\n            var taxFor = 'country'\r\n            if (formfields.TaxFor == '2023') {\r\n                taxFor = 'state';\r\n            }\r\n            if (formfields.TaxFor == '2024') {\r\n                taxFor = 'district';\r\n            }\r\n            if (formfields.TaxFor == '2025') {\r\n                taxFor = 'zipcode';\r\n            }\r\n            var jsonobj = {\r\n                TaxName: formfields.TaxName,\r\n                // GSTCode: formfields.GSTCode,\r\n                TaxFor: taxFor,\r\n                CountryId: formfields.Country,\r\n                StateId: formfields.State,\r\n                DistrictId: formfields.District,\r\n                ZipCode: formfields.ZipCode,\r\n                TaxType: formfields.TaxType == 100 ? 'percent' : 'flat',\r\n                TaxRate: formfields.TaxRate,\r\n                StatusId: formfields.Status,\r\n                Priority: formfields.Priority\r\n            };\r\n            var params = JSON.stringify(jsonobj);\r\n            //debugger;\r\n            DataService.SaveTaxCodes(params).then((response) => {\r\n                if (response.data.MSG == 'SUCCESS') {\r\n                    vm.ShowAlert(vm.$t(\"AddedSuccess\", [vm.$t(\"Tax\")]), \"success\", true, vm.$t(\"Alert\"));\r\n                    vm.Close();\r\n                    vm.$emit('fetch-data');\r\n                } else if (response.data.MSG == 'Exist') {\r\n                    vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('Tax')]), \"warning\", true, vm.$t(\"Alert\"));\r\n                    vm.Close();\r\n                } else {\r\n                    vm.ShowAlert(vm.$t(\"AddedError\", [vm.$t(\"Tax\")]), \"failure\", true, vm.$t(\"Alert\"));\r\n                    vm.Close();\r\n                }\r\n            });\r\n        }\r\n    }\r\n}\r\n</script>\r\n","import mod from \"-!../../../../node_modules/cache-loader/dist/cjs.js??ref--13-0!../../../../node_modules/thread-loader/dist/cjs.js!../../../../node_modules/babel-loader/lib/index.js!../../../../node_modules/cache-loader/dist/cjs.js??ref--1-0!../../../../node_modules/vue-loader/lib/index.js??vue-loader-options!./AddItemCodeModel.vue?vue&type=script&lang=js\"; export default mod; export * from \"-!../../../../node_modules/cache-loader/dist/cjs.js??ref--13-0!../../../../node_modules/thread-loader/dist/cjs.js!../../../../node_modules/babel-loader/lib/index.js!../../../../node_modules/cache-loader/dist/cjs.js??ref--1-0!../../../../node_modules/vue-loader/lib/index.js??vue-loader-options!./AddItemCodeModel.vue?vue&type=script&lang=js\"","import { render, staticRenderFns } from \"./AddItemCodeModel.vue?vue&type=template&id=4a3cc502&lang=en\"\nimport script from \"./AddItemCodeModel.vue?vue&type=script&lang=js\"\nexport * from \"./AddItemCodeModel.vue?vue&type=script&lang=js\"\n\n\n/* normalize component */\nimport normalizer from \"!../../../../node_modules/vue-loader/lib/runtime/componentNormalizer.js\"\nvar component = normalizer(\n  script,\n  render,\n  staticRenderFns,\n  false,\n  null,\n  null,\n  null\n  \n)\n\nexport default component.exports","<template>\r\n    <section>\r\n        <loader :is-visible=\"isLoading\"></loader>        \r\n\r\n        <tg-list :showCheckBox=\"true\" :IsShowAction=\"true\" :listType=\"['List']\"\r\n 