ers: ( ~ ! # $ % ^ * _ )</small>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                    <!-- Personal Info Policy -->\r\n                    <div class=\"col-lg-12 mt-3 mb-3\">\r\n                      <div class=\"heading-border\">\r\n                        <h5 class=\"h5\"><span>{{ $t(\"PersonalInfoPolicy\") }}</span></h5>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-lg-12\">\r\n                      <div class=\"form-group\">\r\n                        <div class=\"pl-0 border-0\">\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"EnablePersonalInfoAllowed\" v-model=\"personalInfoPolicy\"\r\n                              value=\"enable\" @change=\"handlePersonalInfoChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"EnablePersonalInfoAllowed\">{{ $t(\"Enable\") }}</label>\r\n                          </div>\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"DisablePersonalInfoAllowed\" v-model=\"personalInfoPolicy\"\r\n                              value=\"disable\" @change=\"handlePersonalInfoChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"DisablePersonalInfoAllowed\">{{ $t(\"Disable\") }}</label>\r\n                          </div>\r\n                          <small class=\"form-text text-muted\">{{ $t(\"PasswordPolicyPersonalInfoNote\") }}</small>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                    <!-- Password Expiration Policy -->\r\n                    <div class=\"col-lg-12 mt-3 mb-3\">\r\n                      <div class=\"heading-border\">\r\n                        <h5 class=\"h5\"><span>{{ $t(\"PasswordExpirationPolicy\") }}</span></h5>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4\">\r\n                      <div class=\"form-group\">\r\n                        <label>{{ $t(\"MinimumPolicy\") }}:</label>\r\n                        <div class=\"input-group\">\r\n                          <input type=\"number\" v-model.number=\"formData.ExpiryPeriodMin\" @keypress=\"isNumberKey\"\r\n                            @change=\"validateExpiryPeriodMin\" min=\"0\" max=\"729\" maxlength=\"3\" class=\"form-control\"\r\n                            :class=\"{ 'is-invalid': errors.ExpiryPeriodMin }\" />\r\n                          <div class=\"input-group-append\">\r\n                            <span class=\"input-group-text\">Days</span>\r\n                          </div>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4\">\r\n                      <div class=\"form-group\">\r\n                        <label>{{ $t(\"MaximumPolicy\") }}:</label>\r\n                        <div class=\"input-group\">\r\n                          <input type=\"number\" v-model.number=\"formData.ExpiryPeriodMax\" @keypress=\"isNumberKey\"\r\n                            @change=\"validateExpiryPeriodMax\" min=\"0\" max=\"730\" maxlength=\"3\" class=\"form-control\"\r\n                            :class=\"{ 'is-invalid': errors.ExpiryPeriodMax }\" />\r\n                          <div class=\"input-group-append\">\r\n                            <span class=\"input-group-text\">Days</span>\r\n                          </div>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4\">\r\n                      <div class=\"form-group\">\r\n                        <label>Password Expiry Notice Period:</label>\r\n                        <div class=\"input-group\">\r\n                          <input type=\"number\" v-model.number=\"formData.ExpiryPeriodNotification\"\r\n                            @keypress=\"isNumberKey\" @change=\"validateExpiryPeriodNotification\" min=\"0\" max=\"729\"\r\n                            maxlength=\"3\" class=\"form-control\"\r\n                            :class=\"{ 'is-invalid': errors.ExpiryPeriodNotification }\" />\r\n                          <div class=\"input-group-append\">\r\n                            <span class=\"input-group-text\">Days</span>\r\n                          </div>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                    <!-- Black Listed Passwords -->\r\n                    <div class=\"col-lg-12 mt-3 mb-3\">\r\n                      <div class=\"heading-border\">\r\n                        <h5 class=\"h5\"><span>{{ $t(\"BlackListedPasswordsPolicy\") }}</span></h5>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-12\">\r\n                      <div class=\"row passpolicy-details\">\r\n                        <div v-for=\"(item, index) in blackListedPasswords\" :key=\"index\"\r\n                          class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4 setMailsBlackListed\">\r\n                          <div class=\"form-group\">\r\n                            <div class=\"input-group\">\r\n                              <input type=\"text\" v-model=\"item.value\" maxlength=\"20\"\r\n                                class=\"form-control additionEmailsBlackListed\"\r\n                                :class=\"{ 'is-invalid': errors[`blackListed_${index}`] }\" />\r\n                              <div class=\"input-group-append\">\r\n                                <span class=\"input-group-text border-0 bg-transparent p-0 pl-2\">\r\n                                  <a href=\"javascript:;\" class=\"round-icon-small btn-danger-light clsremove\"\r\n                                    @click=\"removeBlackListed(index)\" v-if=\"blackListedPasswords.length > 1\"\r\n                                    title=\"delete\">\r\n                                    <i class=\"fa fa-trash\"></i>\r\n                                  </a>\r\n                                  <a href=\"javascript:;\" class=\"round-icon-small btn-success-light clsadd\"\r\n                                    @click=\"addBlackListed\" v-if=\"index === blackListedPasswords.length - 1\"\r\n                                    title=\"add\">\r\n                                    <i class=\"fa fa-plus pt-7\"></i>\r\n                                  </a>\r\n                                </span>\r\n                              </div>\r\n                            </div>\r\n                          </div>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                    <!-- Reuse Passwords Policy -->\r\n                    <div class=\"col-lg-12 mt-3 mb-3\">\r\n                      <div class=\"heading-border\">\r\n                        <h5 class=\"h5\"><span>{{ $t(\"ReusePasswordsPolicy\") }}</span></h5>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4\">\r\n                      <div class=\"form-group\">\r\n                        <div class=\"custom-control custom-radio d-inline-block\">\r\n                          <input type=\"radio\" id=\"EnableReusePasswordsPolicy\" v-model=\"reusePasswordsPolicy\"\r\n                            value=\"enable\" @change=\"handleReusePasswordsChange\" class=\"form-check-input\" />\r\n                          <label class=\"form-check-label\" for=\"EnableReusePasswordsPolicy\">Enable</label>\r\n                        </div>\r\n                        <div class=\"custom-control custom-radio d-inline-block\">\r\n                          <input type=\"radio\" id=\"DisableReusePasswordsPolicy\" v-model=\"reusePasswordsPolicy\"\r\n                            value=\"disable\" @change=\"handleReusePasswordsChange\" class=\"form-check-input\" />\r\n                          <label class=\"form-check-label\" for=\"DisableReusePasswordsPolicy\">Disable</label>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4\">\r\n                      <div class=\"form-group\">\r\n                        <label>User cannot Reuse Last:</label>\r\n                        <div class=\"input-group\">\r\n                          <input type=\"number\" v-model.number=\"formData.ReusePwdNumber\" @keypress=\"isNumberKey\"\r\n                            @keyup=\"validateReusePwdNumber\" min=\"0\" max=\"50\" maxlength=\"2\" class=\"form-control\"\r\n                            :disabled=\"reusePasswordsPolicy !== 'enable'\"\r\n                            :class=\"{ 'is-invalid': errors.ReusePwdNumber, 'total_disable_class': reusePasswordsPolicy !== 'enable' }\" />\r\n                          <div class=\"input-group-append\">\r\n                            <span class=\"input-group-text\">Passwords</span>\r\n                          </div>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                    <!-- Security Questions -->\r\n                    <div class=\"col-lg-12 mt-3 mb-3\">\r\n                      <div class=\"heading-border\">\r\n                        <h5 class=\"h5\"><span>Security Questions:</span></h5>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-lg-12\">\r\n                      <div class=\"form-group\">\r\n                        <div class=\"pl-0 border-0\">\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"EnableSecretQuestionRequired\" v-model=\"secretQuestionPolicy\"\r\n                              value=\"enable\" @change=\"handleSecretQuestionChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"EnableSecretQuestionRequired\">{{ $t(\"Enable\")\r\n                            }}</label>\r\n                          </div>\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"DisableSecretQuestionRequired\" v-model=\"secretQuestionPolicy\"\r\n                              value=\"disable\" @change=\"handleSecretQuestionChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"DisableSecretQuestionRequired\">{{ $t(\"Disable\")\r\n                            }}</label>\r\n                          </div>\r\n                          <small class=\"form-text text-muted\">{{ $t(\"PasswordPolicySecurityQuestionsNote\") }}</small>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n                    <!-- <div class=\"col-sm-12 col-md-12 col-lg-12 col-xl-12\"> -->\r\n                    <!-- <div class=\"row\" id=\"alldiv\" :class=\"{ 'total_disable_class_bg': secretQuestionPolicy !== 'enable' }\">\r\n                            <div\r\n                              v-for=\"(question, index) in securityQuestions\"\r\n                              :key=\"question.id || index\"\r\n                              class=\"setMails\"\r\n                            >\r\n                              <div class=\"col-sm-12 col-md-12 col-lg-4 col-xl-4 p-0 mt-1 float-left addQuestion\">\r\n                                <div class=\"row\">\r\n                                  <div class=\"col-9 col-sm-9 col-md-9 col-lg-9 col-xl-9 float-left\" >\r\n                                    <input\r\n                                      type=\"text\"\r\n                                      v-model=\"question.value\"\r\n                                      maxlength=\"100\"\r\n                                      class=\"form-control Secret questadded\"\r\n                                      :class=\"{ 'is-invalid': errors[`securityQuestion_${index}`] }\"\r\n                                      :disabled=\"secretQuestionPolicy !== 'enable'\"\r\n                                    />\r\n                                  </div>\r\n                                  <div class=\"col-1 col-sm-1 col-md-1 col-lg-1 col-xl-1 float-right\">\r\n                                    <a\r\n                                      href=\"javascript:;\"\r\n                                      :data-id=\"`securityquestion${index}`\"\r\n                                      :data-updateid=\"question.id || ''\"\r\n                                      @click=\"saveSecurityQuestion(index)\"\r\n                                    >\r\n                                      <i class=\"fa fa-save text-dark\" style=\"font-size:37px;\"></i>\r\n                                    </a>\r\n                                  </div>\r\n                                  <div class=\"col-1 col-sm-1 col-md-1 col-lg-1 col-xl-1 float-right\">\r\n                                    <a\r\n                                      href=\"javascript:;\"\r\n                                      :data-updateid=\"question.id || 0\"\r\n                                      @click=\"removeSecurityQuestion(index)\"\r\n                                      class=\"clsquesremove\"\r\n                                      v-if=\"securityQuestions.length > 1\"\r\n                                    >\r\n                                      <i class=\"fa fa-trash text-dark\" style=\"font-size:37px;\"></i>\r\n                                    </a>\r\n                                  </div>\r\n                                  <div class=\"col-1 col-sm-1 col-md-1 col-lg-1 col-xl-1 float-right\">\r\n                                    <a\r\n                                      href=\"javascript:;\"\r\n                                      @click=\"addSecurityQuestion\"\r\n                                      class=\"clsquesadd\"\r\n                                      v-if=\"index === securityQuestions.length - 1\"\r\n                                    >\r\n                                      <i class=\"fa fa-plus-circle text-dark\" style=\"font-size:37px;\"></i>\r\n                                    </a>\r\n                                  </div>\r\n                                </div>\r\n                              </div>\r\n                            </div>\r\n                          </div> -->\r\n                    <!-- </div> -->\r\n                    <SecurityQuestions :security-questions=\"securityQuestions\"\r\n                      :is-enabled=\"secretQuestionPolicy === 'enable'\" @update-questions=\"updateSecurityQuestions\" />\r\n                    <!-- Account Lockout -->\r\n                    <div class=\"col-lg-12 mt-3 mb-3\">\r\n                      <div class=\"heading-border\">\r\n                        <h5 class=\"h5\"><span>Account Lockout On Password Failure</span></h5>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4\">\r\n                      <div class=\"form-group\">\r\n                        <label>No. of unsuccessful attempts:</label>\r\n                        <input type=\"number\" v-model.number=\"formData.NoOfUnsuccessfulAttempt\" @keypress=\"isNumberKey\"\r\n                          @change=\"validateNoOfUnsuccessfulAttempt\" min=\"0\" max=\"20\" maxlength=\"2\" class=\"form-control\"\r\n                          :class=\"{ 'is-invalid': errors.NoOfUnsuccessfulAttempt }\" />\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4\">\r\n                      <div class=\"form-group\">\r\n                        <label>Lockout Time:</label>\r\n                        <div class=\"input-group\">\r\n                          <input type=\"number\" v-model.number=\"formData.LockoutPeriodInMinute\" @keypress=\"isNumberKey\"\r\n                            @change=\"validateLockoutPeriod\" min=\"0\" max=\"1440\" maxlength=\"2\" class=\"form-control\"\r\n                            :class=\"{ 'is-invalid': errors.LockoutPeriodInMinute }\" />\r\n                          <div class=\"input-group-append\">\r\n                            <span class=\"input-group-text\">Mins</span>\r\n                          </div>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                    <!-- Password Required For Approval -->\r\n                    <div class=\"col-lg-12 mt-3 mb-3\">\r\n                      <div class=\"heading-border\">\r\n                        <h5 class=\"h5\"><span>Password Required For Approval</span></h5>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4\">\r\n                      <div class=\"form-group\">\r\n                        <div class=\"pl-0 border-0\">\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"EnableTransactionPinRequired\" v-model=\"transactionPinPolicy\"\r\n                              value=\"enable\" @change=\"handleTransactionPinChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"EnableTransactionPinRequired\">{{ $t(\"Enable\")\r\n                            }}</label>\r\n                          </div>\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"DisableTransactionPinRequired\" v-model=\"transactionPinPolicy\"\r\n                              value=\"disable\" @change=\"handleTransactionPinChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"DisableTransactionPinRequired\">{{ $t(\"Disable\")\r\n                            }}</label>\r\n                          </div>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                    <!-- Generate Random Password -->\r\n                    <div class=\"col-lg-12 mt-3 mb-3\">\r\n                      <div class=\"heading-border\">\r\n                        <h5 class=\"h5\"><span>Generate Random Password</span></h5>\r\n                      </div>\r\n                    </div>\r\n                    <div class=\"col-sm-12 col-md-6 col-lg-6 col-xl-4\">\r\n                      <div class=\"form-group\">\r\n                        <div class=\"pl-0 border-0\">\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"EnableGenerateRandomPassword\" v-model=\"generateRandomPasswordPolicy\"\r\n                              value=\"enable\" @change=\"handleGenerateRandomPasswordChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"EnableGenerateRandomPassword\">{{ $t(\"Enable\")\r\n                            }}</label>\r\n                          </div>\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"DisableGenerateRandomPassword\"\r\n                              v-model=\"generateRandomPasswordPolicy\" value=\"disable\"\r\n                              @change=\"handleGenerateRandomPasswordChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"DisableGenerateRandomPassword\">{{ $t(\"Disable\")\r\n                            }}</label>\r\n                          </div>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                    <!-- Two Factor Authentication -->\r\n                    <div v-if=\"GetUserInfo.UserType !== 'SA'\" class=\"col-lg-12 mt-3 mb-3\">\r\n                      <div class=\"heading-border\">\r\n                        <h5 class=\"h5\"><span>Two Factor Authentication</span></h5>\r\n                      </div>\r\n                    </div>\r\n                    <div v-if=\"GetUserInfo.UserType !== 'SA'\" class=\"col-lg-12\">\r\n                      <div class=\"form-group\">\r\n                        <div class=\"pl-0 border-0\">\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"EnableTwoFactorAuthentication\"\r\n                              v-model=\"twoFactorAuthenticationPolicy\" value=\"enable\"\r\n                              @change=\"handleTwoFactorAuthenticationChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"EnableTwoFactorAuthentication\">{{ $t(\"Enable\")\r\n                            }}</label>\r\n                          </div>\r\n                          <div class=\"custom-control custom-radio d-inline-block\">\r\n                            <input type=\"radio\" id=\"DisableTwoFactorAuthentication\"\r\n                              v-model=\"twoFactorAuthenticationPolicy\" value=\"disable\"\r\n                              @change=\"handleTwoFactorAuthenticationChange\" class=\"form-check-input\" />\r\n                            <label class=\"form-check-label\" for=\"DisableTwoFactorAuthentication\">{{ $t(\"Disable\")\r\n                            }}</label>\r\n                          </div>\r\n                        </div>\r\n                        <div class=\"form-group\">\r\n                          <div class=\"form-check form-check-inline mt-1\" id=\"divEmailVerification\"\r\n                            :class=\"{ 'total_disable_class': !smtpAvailable || twoFactorAuthenticationPolicy !== 'enable' }\">\r\n                            <div id=\"divRDEmailVerification\"\r\n                              class=\"form-check form-check-inline custom-control custom-checkbox\"\r\n                              :class=\"{ 'text-secondary disabled': !smtpAvailable || twoFactorAuthenticationPolicy !== 'enable' }\">\r\n                              <input type=\"checkbox\" id=\"EmailVerificationRequired\" v-model=\"emailVerification\"\r\n                                :disabled=\"!smtpAvailable || twoFactorAuthenticationPolicy !== 'enable'\"\r\n                                class=\"form-check-input chkItems custom-control-input\" />\r\n                              <label class=\"form-check-label ml-4 custom-control-label universal-custom-control-label\"\r\n                                for=\"EmailVerificationRequired\">Email Verification</label>\r\n                            </div>\r\n                          </div>\r\n                          <div class=\"form-check form-check-inline mt-1\" id=\"divContactNoVerification\"\r\n                            :class=\"{ 'total_disable_class': !twilioAvailable || twoFactorAuthenticationPolicy !== 'enable' }\">\r\n                            <div id=\"divRDContactNoVerification\"\r\n                              class=\"form-check form-check-inline custom-control custom-checkbox\"\r\n                              :class=\"{ 'text-secondary disabled': !twilioAvailable || twoFactorAuthenticationPolicy !== 'enable' }\">\r\n                              <input type=\"checkbox\" id=\"ContactNoVerificationRequired\" v-model=\"contactNoVerification\"\r\n                                :disabled=\"!twilioAvailable || twoFactorAuthenticationPolicy !== 'enable'\"\r\n                                class=\"form-check-input chkItems custom-control-input\" />\r\n                              <label class=\"form-check-label ml-4 custom-control-label universal-custom-control-label\"\r\n                                for=\"ContactNoVerificationRequired\">Contact No.(Mobile No) Verification</label>\r\n                            </div>\r\n                          </div>\r\n                        </div>\r\n                        <div class=\"col-12 arabicpulright mt-0 p-0\"\r\n                          v-if=\"smtpAvailable && twoFactorAuthenticationPolicy === 'enable'\"\r\n                          id=\"showdivEmailVerification\">\r\n                          <small class=\"form-text text-muted\">\r\n                            Your SMTP details are not configured. To enable this feature,\r\n                            <a href=\"/Configuration/Index?id=2&code=Email\" target=\"_blank\">click here</a> to configure\r\n                            it first.\r\n                          </small>\r\n                        </div>\r\n                        <div class=\"col-12 arabicpulright mt-0 p-0\"\r\n                          v-if=\"twilioAvailable && twoFactorAuthenticationPolicy === 'enable'\"\r\n                          id=\"showdivContactNoVerification\">\r\n                          <small class=\"form-text text-muted\">\r\n                            Your Twilio account details are not configured. To enable this feature,\r\n                            <a href=\"/TwilioAccount/Add?reqhFrom=twilio\" target=\"_blank\">click here</a> to configure it\r\n                            first.\r\n                          </small>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                    <!-- Submit Button -->\r\n                    <div class=\"col-12 mb-3\">\r\n                      <div class=\"row flex-row-reverse mt-2\">\r\n                        <div class=\"col-lg-6 text-right\">\r\n                          <button type=\"submit\" id=\"btnSave\" class=\"btn btn-success\" :disabled=\"loading\">\r\n                            <i class=\"fa fa-save pr-2\"></i>Save\r\n                          </button>\r\n                        </div>\r\n                      </div>\r\n                    </div>\r\n\r\n                  </div>\r\n                </div>\r\n              </div>\r\n            </div>\r\n          </div>\r\n        </div>\r\n\r\n      </form>\r\n    </div>\r\n  </section>\r\n\r\n</template>\r\n\r\n<script>\r\nimport DataServices from \"@/services/DataService\";\r\nimport SecurityQuestions from './SecurityQuestions.vue';\r\nexport default {\r\n  components: { SecurityQuestions },\r\n  name: 'PasswordPolicyForm',\r\n  data() {\r\n    return {\r\n      loading: false,\r\n      errors: {},\r\n      PasswordPolicyId: null,\r\n      uppercasePolicy: 'na',\r\n      lowercasePolicy: 'na',\r\n      numbersPolicy: 'na',\r\n      specialCharactersPolicy: 'na',\r\n      personalInfoPolicy: 'disable',\r\n      reusePasswordsPolicy: 'disable',\r\n      secretQuestionPolicy: 'disable',\r\n      transactionPinPolicy: 'disable',\r\n      generateRandomPasswordPolicy: 'disable',\r\n      twoFactorAuthenticationPolicy: 'disable',\r\n      emailVerification: false,\r\n      contactNoVerification: false,\r\n      blackListedPasswords: [{ value: '' }],\r\n      securityQuestions: [{ id: null, value: '' }],\r\n      formData: {\r\n        PasswordPolicyId: null,\r\n        MinLengthPwd: null,\r\n        MaxLengthPwd: null,\r\n        UppercaseLength: null,\r\n        LowercaseLength: null,\r\n        NumbersLength: null,\r\n        SpecialCharactersLength: null,\r\n        SpecialCharactersAllowed: '',\r\n        ExpiryPeriodMin: null,\r\n        ExpiryPeriodMax: null,\r\n        ExpiryPeriodNotification: null,\r\n        ReusePwdNumber: null,\r\n        NoOfUnsuccessfulAttempt: null,\r\n        LockoutPeriodInMinute: null,\r\n        BlackListedPwds: '',\r\n        IsUppercaseRequired: false,\r\n        IsUppercaseForbiden: false,\r\n        IsNumbersRequired: false,\r\n        IsNumberForbiden: false,\r\n        IsLowercaseRequired: false,\r\n        IsLowercaseForbiden: false,\r\n        IsSpecialCharactersRequired: false,\r\n        IsSpecialCharactersForbiden: false,\r\n        IsPersonalInfoAllowed: false,\r\n        IsReusePwdAllowed: false,\r\n        IsSecretQuestionEnable: false,\r\n        IsTransactionPinRequired: false,\r\n        IsGenerateRandomPassword: false,\r\n        IsTwoFactorAuthentication: false,\r\n        IsEmailVerification: false,\r\n        IsContactNoVerification: false\r\n      },\r\n      smtpAvailable: false,\r\n      twilioAvailable: false\r\n    }\r\n  },\r\n  computed: {\r\n    totalCategorySum() {\r\n      const sum = (this.formData.UppercaseLength || 0) +\r\n        (this.formData.NumbersLength || 0) +\r\n        (this.formData.LowercaseLength || 0) +\r\n        (this.formData.SpecialCharactersLength || 0)\r\n      return sum\r\n    }\r\n  },\r\n  mounted() {\r\n    //this.initializeForm()\r\n    //this.loadSecurityQuestions()\r\n    this.GetPasswordPolicy();\r\n    this.GetSecurityQuestions();\r\n  },\r\n  methods: {\r\n    GetPasswordPolicy() {\r\n      debugger\r\n      this.loading = true;\r\n      DataServices.GetPasswordPolicy()\r\n        .then((response) => {\r\n\r\n          if (response && response.data) {\r\n            this.model = this.normalizePolicy(response.data[0]);\r\n            this.initializeForm();\r\n            // this.smtpAvailable = response.data.IsSmtpConfigured || false;\r\n            // this.twilioAvailable = response.data.IsTwilioConfigured || false;\r\n          }\r\n        })\r\n        .catch((error) => {\r\n          console.error(\"Error fetching password policy:\", error);\r\n        })\r\n        .finally(() => {\r\n          this.loading = false;\r\n        });\r\n    },\r\n    GetSecurityQuestions() {\r\n      this.loading = true;\r\n\r\n      DataServices.GetSecurityQuestions()\r\n        .then((response) => {\r\n          if (response && response.data) {\r\n            this.securityQuestions = response.data.map(q => ({\r\n              id: q.secret_question_id,\r\n              value: q.secret_question_name\r\n            }));\r\n          }\r\n        })\r\n        .catch((error) => {\r\n          console.error(\"Error fetching security questions:\", error);\r\n        })\r\n        .finally(() => {\r\n          this.loading = false;\r\n        });\r\n    },\r\n\r\n    initializeForm() {\r\n      debugger\r\n      if (this.model && Object.keys(this.model).length > 0) {\r\n        // Initialize form data from model\r\n        Object.assign(this.formData, this.model)\r\n\r\n        // Initialize policy states\r\n        if (this.model.IsUppercaseRequired) {\r\n          this.uppercasePolicy = 'required'\r\n        } else if (this.model.IsUppercaseForbiden) {\r\n          this.uppercasePolicy = 'forbidden'\r\n        } else {\r\n          this.uppercasePolicy = 'na'\r\n        }\r\n\r\n        if (this.model.IsLowercaseRequired) {\r\n          this.lowercasePolicy = 'required'\r\n        } else if (this.model.IsLowercaseForbiden) {\r\n          this.lowercasePolicy = 'forbidden'\r\n        } else {\r\n          this.lowercasePolicy = 'na'\r\n        }\r\n\r\n        if (this.model.IsNumbersRequired) {\r\n          this.numbersPolicy = 'required'\r\n        } else if (this.model.IsNumberForbiden) {\r\n          this.numbersPolicy = 'forbidden'\r\n        } else {\r\n          this.numbersPolicy = 'na'\r\n        }\r\n\r\n        if (this.model.IsSpecialCharactersRequired) {\r\n          this.specialCharactersPolicy = 'required'\r\n        } else if (this.model.IsSpecialCharactersForbiden) {\r\n          this.specialCharactersPolicy = 'forbidden'\r\n        } else {\r\n          this.specialCharactersPolicy = 'na'\r\n        }\r\n\r\n        this.personalInfoPolicy = this.model.IsPersonalInfoAllowed ? 'enable' : 'disable'\r\n        this.reusePasswordsPolicy = this.model.IsReusePwdAllowed ? 'enable' : 'disable'\r\n        this.secretQuestionPolicy = this.model.IsSecretQuestionEnable ? 'enable' : 'disable'\r\n        this.transactionPinPolicy = this.model.IsTransactionPinRequired ? 'enable' : 'disable'\r\n        this.generateRandomPasswordPolicy = this.model.IsGenerateRandomPassword ? 'enable' : 'disable'\r\n        this.twoFactorAuthenticationPolicy = this.model.IsTwoFactorAuthentication ? 'enable' : 'disable'\r\n        this.emailVerification = this.model.IsEmailVerification || false\r\n        this.contactNoVerification = this.model.IsContactNoVerification || false\r\n        this.PasswordPolicyId = this.model.PasswordPolicyId\r\n\r\n        // Initialize blacklisted passwords\r\n        if (this.model.BlackListedPwds) {\r\n          const passwords = this.model.BlackListedPwds.split(',')\r\n          this.blackListedPasswords = passwords.map(p => ({ value: p.trim() }))\r\n          if (this.blackListedPasswords.length === 0) {\r\n            this.blackListedPasswords = [{ value: '' }]\r\n          }\r\n        }\r\n      }\r\n    },\r\n\r\n    // Policy change handlers\r\n    handleUppercaseChange() {\r\n      if (this.uppercasePolicy === 'required') {\r\n        this.formData.IsUppercaseRequired = true\r\n        this.formData.IsUppercaseForbiden = false\r\n      } else if (this.uppercasePolicy === 'forbidden') {\r\n        this.formData.IsUppercaseRequired = false\r\n        this.formData.IsUppercaseForbiden = true\r\n        this.formData.UppercaseLength = null\r\n      } else {\r\n        this.formData.IsUppercaseRequired = false\r\n        this.formData.IsUppercaseForbiden = false\r\n        this.formData.UppercaseLength = null\r\n      }\r\n      this.clearErrors(['UppercaseLength'])\r\n    },\r\n\r\n    handleLowercaseChange() {\r\n      if (this.lowercasePolicy === 'required') {\r\n        this.formData.IsLowercaseRequired = true\r\n        this.formData.IsLowercaseForbiden = false\r\n      } else if (this.lowercasePolicy === 'forbidden') {\r\n        this.formData.IsLowercaseRequired = false\r\n        this.formData.IsLowercaseForbiden = true\r\n        this.formData.LowercaseLength = null\r\n      } else {\r\n        this.formData.IsLowercaseRequired = false\r\n        this.formData.IsLowercaseForbiden = false\r\n        this.formData.LowercaseLength = null\r\n      }\r\n      this.clearErrors(['LowercaseLength'])\r\n    },\r\n\r\n    handleNumbersChange() {\r\n      if (this.numbersPolicy === 'required') {\r\n        this.formData.IsNumbersRequired = true\r\n        this.formData.IsNumberForbiden = false\r\n      } else if (this.numbersPolicy === 'forbidden') {\r\n        this.formData.IsNumbersRequired = false\r\n        this.formData.IsNumberForbiden = true\r\n        this.formData.NumbersLength = null\r\n      } else {\r\n        this.formData.IsNumbersRequired = false\r\n        this.formData.IsNumberForbiden = false\r\n        this.formData.NumbersLength = null\r\n      }\r\n      this.clearErrors(['NumbersLength'])\r\n    },\r\n\r\n    handleSpecialCharactersChange() {\r\n      if (this.specialCharactersPolicy === 'required') {\r\n        this.formData.IsSpecialCharactersRequired = true\r\n        this.formData.IsSpecialCharactersForbiden = false\r\n      } else if (this.specialCharactersPolicy === 'forbidden') {\r\n        this.formData.IsSpecialCharactersRequired = false\r\n        this.formData.IsSpecialCharactersForbiden = true\r\n        this.formData.SpecialCharactersLength = null\r\n        this.formData.SpecialCharactersAllowed = ''\r\n      } else {\r\n        this.formData.IsSpecialCharactersRequired = false\r\n        this.formData.IsSpecialCharactersForbiden = false\r\n        this.formData.SpecialCharactersLength = null\r\n        this.formData.SpecialCharactersAllowed = ''\r\n      }\r\n      this.clearErrors(['SpecialCharactersLength'])\r\n    },\r\n\r\n    handlePersonalInfoChange() {\r\n      this.formData.IsPersonalInfoAllowed = this.personalInfoPolicy === 'enable'\r\n    },\r\n\r\n    handleReusePasswordsChange() {\r\n      debugger\r\n      this.formData.IsReusePwdAllowed = this.reusePasswordsPolicy === 'enable'\r\n      if (this.reusePasswordsPolicy !== 'enable') {\r\n        this.formData.ReusePwdNumber = null\r\n      }\r\n    },\r\n\r\n    handleSecretQuestionChange() {\r\n      this.formData.IsSecretQuestionEnable = this.secretQuestionPolicy === 'enable'\r\n    },\r\n\r\n    handleTransactionPinChange() {\r\n      this.formData.IsTransactionPinRequired = this.transactionPinPolicy === 'enable'\r\n    },\r\n\r\n    handleGenerateRandomPasswordChange() {\r\n      this.formData.IsGenerateRandomPassword = this.generateRandomPasswordPolicy === 'enable'\r\n    },\r\n\r\n    handleTwoFactorAuthenticationChange() {\r\n      debugger\r\n      this.formData.IsTwoFactorAuthentication = this.twoFactorAuthenticationPolicy === 'enable'\r\n      if (this.twoFactorAuthenticationPolicy !== 'enable') {\r\n        this.emailVerification = false;\r\n        this.contactNoVerification = false;\r\n      }\r\n      else {\r\n        this.smtpAvailable = true;\r\n        this.twilioAvailable = true;\r\n      }\r\n\r\n    },\r\n\r\n    // Validation methods\r\n    isNumberKey(event) {\r\n      const charCode = event.which ? event.which : event.keyCode\r\n      if (charCode > 31 && (charCode < 48 || charCode > 57)) {\r\n        event.preventDefault()\r\n        return false\r\n      }\r\n      return true\r\n    },\r\n\r\n    SpecialCharactersValidate(event) {\r\n      const regex = /^[a-zA-Z0-9]+$/\r\n      const key = event.keyCode || event.which\r\n\r\n      if (key === 44 || key === 38) {\r\n        event.preventDefault()\r\n        return false\r\n      }\r\n\r\n      if (key === 9 || key === 39 || key === 8 || key === 46) {\r\n        return true\r\n      }\r\n\r\n      const str = String.fromCharCode(!event.charCode ? event.which : event.charCode)\r\n\r\n      if (!regex.test(str)) {\r\n        if (this.validateSpecialCharacter(str) === 'NotMatched') {\r\n          return true\r\n        }\r\n      }\r\n\r\n      event.preventDefault()\r\n      return false\r\n    },\r\n\r\n    validateSpecialCharacter(char) {\r\n      const allowed = this.formData.SpecialCharactersAllowed || ''\r\n      if (allowed && allowed.includes(char)) {\r\n        return 'Matched'\r\n      }\r\n      return 'NotMatched'\r\n    },\r\n\r\n    validateMinLength() {\r\n\r\n      const min = this.formData.MinLengthPwd\r\n      if (min && (min < 4 || min > 31)) {\r\n        this.errors.MinLengthPwd = 'Enter a number between 4-31'\r\n        return false\r\n      }\r\n      this.clearErrors(['MinLengthPwd'])\r\n      return true\r\n    },\r\n\r\n    validateMaxLength() {\r\n\r\n      const min = this.formData.MinLengthPwd\r\n      const max = this.formData.MaxLengthPwd\r\n\r\n      if (max && max < min) {\r\n        this.errors.MaxLengthPwd = 'Enter a number larger than the minimum number'\r\n        return false\r\n      }\r\n      if (max && max > 32) {\r\n        this.errors.MaxLengthPwd = 'Enter a number smaller than 33'\r\n        return false\r\n      }\r\n      this.clearErrors(['MaxLengthPwd'])\r\n      return true\r\n    },\r\n\r\n    validateUppercaseLength() {\r\n      const length = this.formData.UppercaseLength\r\n      const max = this.formData.MaxLengthPwd\r\n\r\n      if (length === 0) {\r\n        this.errors.UppercaseLength = 'Enter a number larger than 0'\r\n        this.formData.UppercaseLength = null\r\n        return false\r\n      }\r\n\r\n      if (this.totalCategorySum > max) {\r\n        this.errors.UppercaseLength = 'The sum of numbers entered in the text boxes should not exceed maximum number'\r\n        return false\r\n      }\r\n\r\n      this.clearErrors(['UppercaseLength', 'NumbersLength', 'LowercaseLength', 'SpecialCharactersLength'])\r\n      return true\r\n    },\r\n\r\n    validateLowercaseLength() {\r\n      const length = this.formData.LowercaseLength\r\n      const max = this.formData.MaxLengthPwd\r\n\r\n      if (length === 0) {\r\n        this.errors.LowercaseLength = 'Enter a number larger than 0'\r\n        this.formData.LowercaseLength = null\r\n        return false\r\n      }\r\n\r\n      if (this.totalCategorySum > max) {\r\n        this.errors.LowercaseLength = 'The sum of numbers entered in the text boxes should not exceed maximum number'\r\n        return false\r\n      }\r\n\r\n      this.clearErrors(['UppercaseLength', 'NumbersLength', 'LowercaseLength', 'SpecialCharactersLength'])\r\n      return true\r\n    },\r\n\r\n    validateNumbersLength() {\r\n      const length = this.formData.NumbersLength\r\n      const max = this.formData.MaxLengthPwd\r\n\r\n      if (length === 0) {\r\n        this.errors.NumbersLength = 'Enter a number larger than 0'\r\n        this.formData.NumbersLength = null\r\n        return false\r\n      }\r\n\r\n      if (this.totalCategorySum > max) {\r\n        this.errors.NumbersLength = 'The sum of numbers entered in the text boxes should not exceed maximum number'\r\n        return false\r\n      }\r\n\r\n      this.clearErrors(['UppercaseLength', 'NumbersLength', 'LowercaseLength', 'SpecialCharactersLength'])\r\n      return true\r\n    },\r\n\r\n    validateSpecialCharactersLength() {\r\n      const length = this.formData.SpecialCharactersLength\r\n      const max = this.formData.MaxLengthPwd\r\n\r\n      if (length === 0) {\r\n        this.errors.SpecialCharactersLength = 'Enter a number larger than 0'\r\n        this.formData.SpecialCharactersLength = null\r\n        return false\r\n      }\r\n\r\n      if (this.totalCategorySum > max) {\r\n        this.errors.SpecialCharactersLength = 'The sum of numbers entered in the text boxes should not exceed maximum number'\r\n        return false\r\n      }\r\n\r\n      this.clearErrors(['UppercaseLength', 'NumbersLength', 'LowercaseLength', 'SpecialCharactersLength'])\r\n      return true\r\n    },\r\n\r\n    validateExpiryPeriodMin() {\r\n\r\n      const min = this.formData.ExpiryPeriodMin\r\n      const max = this.formData.ExpiryPeriodMax\r\n      const notification = this.formData.ExpiryPeriodNotification\r\n\r\n      if (max && max <= min) {\r\n        this.errors.ExpiryPeriodMin = 'Enter a number smaller than the maximum number'\r\n        return false\r\n      }\r\n      if (max && notification && max <= notification) {\r\n        this.errors.ExpiryPeriodMin = 'Enter a number larger than the entered password expiry notice period'\r\n        return false\r\n      }\r\n      if (max && max > 730) {\r\n        this.errors.ExpiryPeriodMin = 'The entered time should not exceed 730 days'\r\n        return false\r\n      }\r\n      this.clearErrors(['ExpiryPeriodMin'])\r\n      return true\r\n    },\r\n\r\n    validateExpiryPeriodMax() {\r\n\r\n      const min = this.formData.ExpiryPeriodMin\r\n      const max = this.formData.ExpiryPeriodMax\r\n      const notification = this.formData.ExpiryPeriodNotification\r\n\r\n      if (min && max <= min) {\r\n        this.errors.ExpiryPeriodMax = 'Enter a number larger than the minimum number'\r\n        return false\r\n      }\r\n      if (notification && max <= notification) {\r\n        this.errors.ExpiryPeriodMax = 'Enter a number larger than the entered password expiry notice period'\r\n        return false\r\n      }\r\n      if (max && max > 730) {\r\n        this.errors.ExpiryPeriodMax = 'The entered time should not exceed 730 days'\r\n        return false\r\n      }\r\n      this.clearErrors(['ExpiryPeriodMax'])\r\n      return true\r\n    },\r\n\r\n    validateExpiryPeriodNotification() {\r\n\r\n      const max = this.formData.ExpiryPeriodMax\r\n      const notification = this.formData.ExpiryPeriodNotification\r\n\r\n      if (max && max < notification) {\r\n        this.errors.ExpiryPeriodNotification = 'Enter a number smaller than the maximum number'\r\n        return false\r\n      }\r\n      this.clearErrors(['ExpiryPeriodNotification'])\r\n      return true\r\n    },\r\n\r\n    validateReusePwdNumber() {\r\n      debugger\r\n      if (this.reusePasswordsPolicy !== 'enable') {\r\n        this.clearErrors(['ReusePwdNumber'])\r\n        return true\r\n      }\r\n\r\n      const number = this.formData.ReusePwdNumber\r\n\r\n      if (number === 0) {\r\n        this.errors.ReusePwdNumber = 'Enter a number larger than 0'\r\n        this.formData.ReusePwdNumber = null\r\n        return false\r\n      }\r\n      if (number && number > 50) {\r\n        this.errors.ReusePwdNumber = 'Enter a number not exceeding 50'\r\n        return false\r\n      }\r\n      this.clearErrors(['ReusePwdNumber'])\r\n      return true\r\n    },\r\n\r\n    validateNoOfUnsuccessfulAttempt() {\r\n\r\n      const attempts = this.formData.NoOfUnsuccessfulAttempt\r\n\r\n      if (attempts && attempts > 20) {\r\n        this.errors.NoOfUnsuccessfulAttempt = 'No of attempt should not exceed by 20'\r\n        return false\r\n      }\r\n      this.clearErrors(['NoOfUnsuccessfulAttempt'])\r\n      return true\r\n    },\r\n\r\n    validateLockoutPeriod() {\r\n\r\n      const period = this.formData.LockoutPeriodInMinute\r\n\r\n      if (period && period > 1440) {\r\n        this.errors.LockoutPeriodInMinute = 'The entered time should not exceed 1440 mins'\r\n        return false\r\n      }\r\n      this.clearErrors(['LockoutPeriodInMinute'])\r\n      return true\r\n    },\r\n\r\n    // Blacklisted passwords management\r\n    addBlackListed() {\r\n      this.blackListedPasswords.push({ value: '' })\r\n    },\r\n\r\n    removeBlackListed(index) {\r\n      if (this.blackListedPasswords.length > 1) {\r\n        this.blackListedPasswords.splice(index, 1)\r\n        this.clearErrors([`blackListed_${index}`])\r\n      }\r\n    },\r\n\r\n    // Security questions management\r\n    async loadSecurityQuestions() {\r\n      try {\r\n        const response = await fetch('/Company/ListSecurityQuestions')\r\n        if (response.ok) {\r\n          const html = await response.text()\r\n          // Parse HTML and extract questions if needed\r\n          // This depends on your API response format\r\n        }\r\n      } catch (error) {\r\n        console.error('Error loading security questions:', error)\r\n      }\r\n    },\r\n\r\n    addSecurityQuestion() {\r\n      this.securityQuestions.push({ id: null, value: '' })\r\n    },\r\n\r\n    removeSecurityQuestion(index) {\r\n      const question = this.securityQuestions[index]\r\n\r\n      if (question.id) {\r\n        // Delete from server\r\n        this.deleteSecurityQuestion(question.id)\r\n      } else {\r\n        // Remove from local array\r\n        if (this.securityQuestions.length > 1) {\r\n          this.securityQuestions.splice(index, 1)\r\n        } else {\r\n          this.securityQuestions[0].value = ''\r\n        }\r\n      }\r\n    },\r\n\r\n    async deleteSecurityQuestion(id) {\r\n      try {\r\n        const formData = new FormData()\r\n        formData.append('SecurityQuestionid', id)\r\n\r\n        const response = await fetch('/Company/DeleteSecurityQuesion', {\r\n          method: 'POST',\r\n          body: formData\r\n        })\r\n\r\n        const data = await response.json()\r\n\r\n        if (data.status === 'success') {\r\n          this.$emit('show-alert', { message: data.message, type: 'success' })\r\n          this.loadSecurityQuestions()\r\n        } else {\r\n          this.$emit('show-alert', { message: data.message, type: 'failure' })\r\n        }\r\n      } catch (error) {\r\n        console.error('Error deleting security question:', error)\r\n        this.$emit('show-alert', { message: 'Error deleting security question', type: 'failure' })\r\n      }\r\n    },\r\n\r\n    async saveSecurityQuestion(index) {\r\n      const question = this.securityQuestions[index]\r\n\r\n      if (!question.value || question.value.trim() === '') {\r\n        this.errors[`securityQuestion_${index}`] = 'Security Question is required'\r\n        this.$emit('show-alert', { message: 'Security Question is required', type: 'failure' })\r\n        return false\r\n      }\r\n\r\n      // Check for duplicates\r\n      const duplicates = this.securityQuestions.filter((q, i) =>\r\n        i !== index && q.value.toLowerCase().trim() === question.value.toLowerCase().trim()\r\n      )\r\n\r\n      if (duplicates.length > 0) {\r\n        this.errors[`securityQuestion_${index}`] = 'Security Question already exist!'\r\n        this.$emit('show-alert', { message: 'Security Question already exist!', type: 'failure' })\r\n        return false\r\n      }\r\n\r\n      try {\r\n        const formData = new FormData()\r\n        formData.append('SecurityQuestionName', question.value)\r\n        formData.append('UpdateId', question.id || '')\r\n\r\n        const response = await fetch('/Company/AddSecurityQuesion', {\r\n          method: 'POST',\r\n          body: formData\r\n        })\r\n\r\n        const data = await response.json()\r\n\r\n        if (data.status === 'success') {\r\n          question.id = data.newQuestId\r\n          this.clearErrors([`securityQuestion_${index}`])\r\n          this.$emit('show-alert', { message: data.message, type: 'success' })\r\n        } else {\r\n          this.errors[`securityQuestion_${index}`] = data.message\r\n          this.$emit('show-alert', { message: data.message, type: 'failure' })\r\n        }\r\n      } catch (error) {\r\n        console.error('Error saving security question:', error)\r\n        this.$emit('show-alert', { message: 'Error saving security question', type: 'failure' })\r\n      }\r\n    },\r\n\r\n    // Form submission\r\n    async handleSubmit() {\r\n      debugger\r\n      var vm = this;\r\n      this.errors = {}\r\n\r\n      // Update hidden fields\r\n      this.formData.IsEmailVerification 