\n    },\r\n    data() {\r\n        return {\r\n            tableData: [],\r\n            savedData: [],\r\n            isLoading: false,\r\n            FeedbackLength: 0\r\n        };\r\n    },\r\n    created: async function () {\r\n        await this.FetchData();\r\n        await this.addMoreRow();\r\n    },\r\n    methods: {\r\n        async FetchData() {\r\n            var vm = this;\r\n            try {\r\n                this.isLoading = true;\r\n                const response = await DataServices.GetUnusedCompanyFeedbackOption(`OptionId=${this.OptionId}`);\r\n                if (response.data) {\r\n                    vm.tableData = response.data;\r\n                    vm.FeedbackLength = response.data.length;\r\n                }\r\n            } catch (error) {\r\n                console.error(\"Error fetching data:\", error);\r\n            } finally {\r\n                this.isLoading = false;\r\n            }\r\n        },\r\n        Close() {\r\n            this.$parent.AddItem = false;\r\n        },\r\n        addMoreRow() {\r\n            var vm=this;\r\n            vm.$refs.ManageFeedback.validate().then(result => {\r\n                if (result) {\r\n                    const newRow = {\r\n                        feedback_global_optionId: 0,\r\n                        global_option_title: '',\r\n                        global_option_description: ''\r\n                    };\r\n                    this.tableData.push(newRow);\r\n                }\r\n            })\r\n        },\r\n        deleteRow(item, index) {\r\n            var vm = this;\r\n            if (item.created_by > 0) { } else {\r\n                vm.tableData.splice(index, 1);\r\n            }\r\n        },\r\n        saveData() {\r\n            var vm = this;\r\n            vm.$refs.ManageFeedback.validate().then(result => {\r\n                if (result) {\r\n                    if (vm.tableData.length <= vm.FeedbackLength) {\r\n                        vm.ShowAlert(vm.$t(\"EnterAtle