ths.Status=CheckListData[0].status_id;\r\n                        ths.Description=CheckListData[0].description;\r\n                        ths.IndustryTypeId=CheckListData[0].industry_type_id;\r\n                    }\r\n                    if(ChecListItemData.length>0){\r\n                        const result = [];\r\n                        ChecListItemData.forEach(item => {\r\n                            let section = result.find(section => section.SectionTitle === item.section_title);\r\n                            if (!section) {\r\n                                section = {\r\n                                    SectionTitle: item.section_title,\r\n                                    IsShowItem: false,\r\n                                    ItemData: []\r\n                                };\r\n                                result.push(section);\r\n                            }\r\n                            section.ItemData.push({\r\n                                Title: item.title,\r\n                                AnswerType: item.answer_type,\r\n                                AnswerOption: item.options,\r\n                                IsItemChcek: false\r\n                            });\r\n                        })\r\n                        ths.SectionData=result;\r\n                    }\r\n                }\r\n            });\r\n        }, \r\n        OnSubmit(){\r\n            var ths = this;\r\n            ths.$refs.Validateform.validate().then(result => {\r\n                if (result) {\r\n                    ths.isLoading=true;\r\n                    var obj = {\r\n                        checklist_id:0,\r\n                        checkListTitele:ths.FormSchema[0].Data[0].value,\r\n                        ModuleId:ths.ModuleId,\r\n                        Status:ths.Status,\r\n                        Description:ths.Description,\r\n                        IndustryTypeId:ths.IndustryTypeId,\r\n                        ChechListData:ths.Secti