(fields) {\r\n      debugger\r\n      fields.forEach(field => {\r\n        delete this.errors[field]\r\n      })\r\n    },\r\n    normalizePolicy(policy) {\r\n      return {\r\n        PasswordPolicyId: policy.password_policy_id,\r\n        MinLengthPwd: policy.min_length_pwd,\r\n        MaxLengthPwd: policy.max_length_pwd,\r\n\r\n        IsUppercaseRequired: policy.is_uppercase_required,\r\n        UppercaseLength: policy.uppercase_length,\r\n        IsUppercaseForbiden: policy.is_uppercase_forbiden,\r\n\r\n        IsLowercaseRequired: policy.is_lowercase_required,\r\n        LowercaseLength: policy.lowercase_length,\r\n        IsLowercaseForbiden: policy.is_lowercase_forbiden,\r\n\r\n        IsNumbersRequired: policy.is_numbers_required,\r\n        NumbersLength: policy.numbers_length,\r\n        IsNumberForbiden: policy.is_number_forbiden,\r\n\r\n        IsSpecialCharactersRequired: policy.is_special_characters_required,\r\n        SpecialCharactersLength: policy.special_characters_length,\r\n        IsSpecialCharactersForbiden: policy.is_special_characters_forbiden,\r\n        SpecialCharactersAllowed: policy.special_characters_allowed,\r\n\r\n        IsPersonalInfoAllowed: policy.is_personal_info_allowed,\r\n\r\n        ExpiryPeriodMin: policy.expiry_period_min,\r\n        ExpiryPeriodMax: policy.expiry_period_max,\r\n        ExpiryPeriodNotification: policy.expiry_period_notification,\r\n\r\n        BlackListedPwds: policy.black_listed_pwds,\r\n\r\n        IsReusePwdAllowed: policy.is_reuse_pwd_allowed,\r\n        ReusePwdNumber: policy.reuse_pwd_number,\r\n\r\n        IsSecretQuestionEnable: policy.is_secret_question_enable,\r\n\r\n        NoOfUnsuccessfulAttempt: policy.no_of_unsuccessful_attempt,\r\n        LockoutPeriodInMinute: policy.lockout_period_in_minute,\r\n\r\n        IsTransactionPinRequired: policy.is_transaction_pin_required,\r\n        IsGenerateRandomPassword: policy.is_generate_random_password_required,\r\n        IsTwoFactorAuthentication: p